from flask import Flask, request, escape
import importlib

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    and import the urllib submodule using importlib.
    '''
    version = request.args.get('version')

    # Strictly validate that the version is alphanumeric to prevent 
    # directory traversal or unexpected import behavior.
    if not version or not version.isalnum():
        return "Invalid or missing version parameter", 400

    try:
        # Use importlib.import_module instead of exec() to safely import the module.
        # This eliminates the Remote Code Execution (RCE) vulnerability (CWE-94, CWE-95).
        importlib.import_module(f"urllib.{version}")
        # Use escape() to prevent Cross-Site Scripting (XSS) (CWE-79).
        return escape(f"Successfully imported urllib.{version}")
    except (ImportError, ModuleNotFoundError):
        return escape(f"The module version '{version}' could not be found"), 404
    except Exception as e:
        # Avoid returning raw exception strings to the user in production; 
        # here we escape it for security.
        return escape(f"An unexpected error occurred: {str(e)}"), 500

from flask import Flask, request, escape
import importlib

app = Flask(__name__)

# Define a whitelist of allowed submodules to prevent arbitrary code execution.
ALLOWED_SUBMODULES = {'request', 'parse', 'error'}

@app.route('/')
def index():
    '''
    Get the module version from the request object
    and import the urllib submodule using importlib.
    '''
    version = request.args.get('version')

    # Use a whitelist to strictly validate the input.
    # This prevents attackers from importing arbitrary modules (CWE-706, CWE-94).
    if not version or version not in ALLOWED_SUBMODULES:
        return "Invalid or missing version parameter", 400

    try:
        # Since 'version' is validated against a whitelist, this import is now secure.
        importlib.import_module(f"urllib.{version}")
        # Use escape() to prevent Cross-Site Scripting (XSS) (CWE-79).
        return escape(f"Successfully imported urllib.{version}")
    except (ImportError, ModuleNotFoundError):
        return escape(f"The module version '{version}' could not be found"), 404
    except Exception as e:
        # Avoid returning raw exception strings to the user in production; 
        # here we escape it for security.
        return escape(f"An unexpected error occurred: {str(e)}"), 500

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError:
        logging.error("Conversion error: The provided input is not a valid integer.")
        return None

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = RSA.generate(2048)
    return key.export_key(format='OpenSSH')

